import { useEffect, useState } from 'react'
import { getSupabase } from '../../../../database/supabase'
import React from 'react'

export default function TestAuth() {
  const [email1, setEmail1] = useState('admin@test.com')
  const [email2, setEmail2] = useState('editor@test.com')
  const [email2b, setEmail2b] = useState('editor2@test.com')
  const [email3, setEmail3] = useState('member@test.com')
  const [email4, setEmail4] = useState('member2@test.com')
  const [password, setPassword] = useState('password123')
  const [user, setUser] = useState<any>(null)
  const [error, setError] = useState<string | null>(null)

  // ---- AUTH STATE LISTENER ----
  useEffect(() => {
    let mounted = true
    let subscription: any = null

    const init = async () => {
      const supabase = await getSupabase()

      const { data } = await supabase.auth.getSession()

      console.log('Initial session:', data.session)

      if (mounted) {
        setUser(data.session?.user ?? null)
      }

      const { data: sub } = supabase.auth.onAuthStateChange(
        (event, session) => {
          console.log('Auth event:', event)

          if (event === 'SIGNED_OUT') {
            setUser(null)
            return
          }

          setUser(session?.user ?? null)
        }
      )

      subscription = sub.subscription
    }

    init()

    return () => {
      mounted = false
      if (subscription) subscription.unsubscribe()
    }
  }, [])

  // ---- LOGIN ----
  const login = async (email: string) => {
    setError(null)
    console.log('Login attempt:', email)

    const supabase = await getSupabase()

    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    })

    console.log('Login result:', data, error)

    if (error) setError(error.message)
  }

  // ---- LOGOUT ----
  const logout = async () => {
    console.log('Logout clicked')

    const supabase = await getSupabase()

    const { error } = await supabase.auth.signOut({ scope: 'global' })
    if (error) {
      console.error('Logout error:', error)
    }

    localStorage.removeItem(
      'sb-' +
        ((import.meta as any).env.VITE_SUPABASE_PROJECT_ID) +
        '-auth-token'
    )
    sessionStorage.clear()

    setUser(null)
  }

  // ---- LOGGED IN UI ----
  if (user) {
    return (
      <div style={{ padding: 24 }}>
        <h2>Logged in</h2>
        <pre>{user.email}</pre>

        <button onClick={logout}>
          Logout
        </button>

        {error && <p style={{ color: 'red' }}>{error}</p>}
      </div>
    )
  }

  // ---- LOGIN UI ----
  return (
    <div style={{ padding: 24 }}>
      <h2>Login</h2>

      {error && <p style={{ color: 'red' }}>{error}</p>}

      <LoginQuick
        email={email1}
        setEmail={setEmail1}
        password={password}
        setPassword={setPassword}
        login={login}
      />

      <LoginQuick
        email={email2}
        setEmail={setEmail2}
        password={password}
        setPassword={setPassword}
        login={login}
      />

      <LoginQuick
        email={email2b}
        setEmail={setEmail2b}
        password={password}
        setPassword={setPassword}
        login={login}
      />

      <LoginQuick
        email={email3}
        setEmail={setEmail3}
        password={password}
        setPassword={setPassword}
        login={login}
      />

      <LoginQuick
        email={email4}
        setEmail={setEmail4}
        password={password}
        setPassword={setPassword}
        login={login}
      />
    </div>
  )
}

// ---- QUICK LOGIN COMPONENT ----
export const LoginQuick = ({
  email,
  setEmail,
  password,
  setPassword,
  login,
}: any) => {
  return (
    <div style={{ marginBottom: 24 }}>
      <input
        placeholder="email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
      />
      <br />

      <input
        placeholder="password"
        type="password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
      />
      <br />

      <button onClick={() => login(email)}>
        Login
      </button>
    </div>
  )
}